// Extrai e normaliza dados da mensagem recebida
const from = $input.first().json.from || $input.first().json.number_whatsapp;
const message_text = $input.first().json.text || $input.first().json.message;
const media_type = $input.first().json.mediaType || null;
const media_url = $input.first().json.mediaUrl || null;
const timestamp = $input.first().json.timestamp || new Date().toISOString();

return {
  phone: from,
  text: message_text?.toLowerCase() || '',
  media_type: media_type,
  media_url: media_url,
  timestamp: timestamp,
  language: 'pt-BR'
};

// Detecta tipo de agente: principal, prospecção, objeção ou extra
const lead = $node.lookup_session.json[0];
const subscription = $node.validate_user.json[0];
const objecoes_count = lead?.objecoes_count || 0;
const stage = lead?.stage || 'whatsapp';
const fluxo_id = lead?.fluxo_id || '';

let agent_type = 'principal';
let agent_index = 0;

if (stage === 'objecoes' || objecoes_count > 2) {
  agent_type = 'objecao';
} else if (stage === 'prospecao' || fluxo_id?.includes('prospec')) {
  agent_type = 'prospec';
} else if (subscription?.agentes_extras > 0 && fluxo_id?.match(/ae(\d)/)) {
  agent_type = 'extra';
  const match = fluxo_id.match(/ae(\d)/);
  agent_index = match ? parseInt(match[1]) : 0;
}

return {
  agent_type: agent_type,
  agent_index: agent_index,
  user_id: lead?.user_id || subscription?.id,
  lead_id: lead?.id,
  subscription_status: subscription?.status
};

// Monta system prompt + seleciona provider e modelo dinâmico
const configArray = $node.busca_configs_sdr.json || [];
const configMap = {};

configArray.forEach(item => {
  configMap[item.chave] = item.valor;
});

const agent_type = $node.detect_agent_type.json.agent_type;
const agent_index = $node.detect_agent_type.json.agent_index;
const prefix = agent_type === 'principal' ? '' : agent_type === 'prospec' ? 'prospec_' : agent_type === 'objecao' ? 'ob_' : `ae${agent_index}_`;

// Seleciona prompt base
let sistema_prompt = configMap[`${prefix}sistema_prompt`] || 'Você é um assistente de vendas profissional. Qualifique leads com critério.';

// Seleciona provider
const provider = configMap[`${prefix}ai_provider`] || configMap['ai_provider'] || 'openai';

// Seleciona modelo e parâmetros
let model, temperature, max_tokens;

if (provider === 'openai') {
  model = configMap[`${prefix}openai_model`] || configMap['openai_model'] || 'gpt-4o-mini';
  temperature = parseFloat(configMap[`${prefix}openai_temperature`] || configMap['openai_temperature'] || '0.7');
  max_tokens = parseInt(configMap[`${prefix}openai_max_tokens`] || configMap['openai_max_tokens'] || '1024');
} else if (provider === 'claude') {
  model = configMap[`${prefix}claude_model`] || configMap['claude_model'] || 'claude-haiku-4-5';
  temperature = parseFloat(configMap[`${prefix}claude_temperature`] || configMap['claude_temperature'] || '0.7');
  max_tokens = parseInt(configMap[`${prefix}claude_max_tokens`] || configMap['claude_max_tokens'] || '1024');
} else if (provider === 'google') {
  model = configMap[`${prefix}google_model`] || configMap['google_model'] || 'gemini-2.0-flash';
  temperature = parseFloat(configMap[`${prefix}google_temperature`] || configMap['google_temperature'] || '0.7');
  max_tokens = parseInt(configMap[`${prefix}google_max_tokens`] || configMap['google_max_tokens'] || '1024');
}

// Append tonalidade
if (configMap[`${prefix}tonalidade`]) {
  sistema_prompt += `\n\nTONALIDADE: ${configMap[`${prefix}tonalidade`]}`;
}

// Append critérios
if (configMap[`${prefix}criterios_qualificacao`]) {
  sistema_prompt += `\n\nCRITÉRIOS DE QUALIFICAÇÃO:\n${configMap[`${prefix}criterios_qualificacao`]}`;
}

return {
  final_system_prompt: sistema_prompt,
  ai_provider_ativo: provider,
  ai_model_ativo: model,
  ai_temperature_ativo: temperature,
  ai_max_tokens_ativo: max_tokens,
  msg_qualificado: configMap[`${prefix}msg_qualificado`] || 'Parabéns! Você foi qualificado.',
  msg_desqualificado: configMap[`${prefix}msg_desqualificado`] || 'Obrigado pelo contato.',
  responder_em_audio: configMap[`${prefix}responder_em_audio`] || 'false',
  numero_destino: configMap[`${prefix}numero_destino`],
  grupo_destino: configMap[`${prefix}grupo_destino`],
  notif_destino: configMap['notif_destino'] || 'numero',
  gateway_padrao: configMap['gateway_padrao'] || 'stripe'
};

// Detecta qualificação
const response_text = $node.llm_call.json.content || '';
const has_qualificado = response_text.includes('[LEAD_QUALIFICADO]');
const has_desqualificado = response_text.includes('[LEAD_DESQUALIFICADO]');

let qualification_score = 0;
if (has_qualificado) qualification_score = 100;
else if (has_desqualificado) qualification_score = 0;
else qualification_score = 50;

return {
  qualified: has_qualificado,
  disqualified: has_desqualificado,
  qualification_score: qualification_score
};

// Detecta objeções
const response_text = $node.llm_call.json.content || '';
const objection_keywords = ['não posso', 'muito caro', 'não sei', 'concorrente', 'depois'];

let has_objection = false;
let objection_type = '';

for (const keyword of objection_keywords) {
  if (response_text.toLowerCase().includes(keyword)) {
    has_objection = true;
    if (keyword.includes('caro')) objection_type = 'preco';
    else if (keyword.includes('depois')) objection_type = 'timing';
    else if (keyword.includes('concorrente')) objection_type = 'concorrente';
    else objection_type = 'outro';
    break;
  }
}

return {
  has_objection: has_objection,
  objection_type: objection_type
};

// Detecta intenção de pagamento
const response_text = $node.llm_call.json.content || '';
const payment_keywords = ['quero pagar', 'como pago', 'vou fechar', 'quero comprar', 'valor', 'boleto', 'pix', 'cartão', 'parcelas', '[INICIAR_PAGAMENTO]'];

let payment_intent = false;

for (const keyword of payment_keywords) {
  if (response_text.toLowerCase().includes(keyword.toLowerCase())) {
    payment_intent = true;
    break;
  }
}

return { payment_intent: payment_intent };

// Decide response format
const responder_em_audio = $node.build_system_prompt.json.responder_em_audio === 'true';
return { response_format: responder_em_audio ? 'audio' : 'text' };
